(window.webpackJsonp=window.webpackJsonp||[]).push([[12],{639:function(n,t){n.exports='\x3c!-- \ntitle: 09-数据结构\nsort: \n--\x3e \n\n# 数据结构\n\n## 枚举\n\n```c\nenum COLOR {RED, GREEN, BLUE, colorNum};\nenum COLOR c = GREEN;\nprintf("%d %d %d", RED, colorNum, c);\n// 0 3 1\n```\n\n## 联合体\n\n> 每个实例只能存储一个声明的变量\n>\n> 最多只有一个成员有效\n\n```c\n#include <stdio.h>\n\nunion TestUnion\n{\n    char x;\n    int y;\n};\n\nint main(int argc, char const *argv[])\n{\n\n    union TestUnion test;\n    test.x = \'a\';\n    test.y = 404;\n    printf("size: %d\\nValue: %d", sizeof(test),test.y);\n    // size: 4\n\t// Value: 404\n\n    return 0;\n}\n```\n\n## 结构体\n\n> 请参考: `05-数组与指针`\n\n```c\n#include <stdio.h>\n\nint main()\n{\n\tstruct point {\n\t\tint x;\n\t\tint y;\n\t}place;\n    // struct point place;\n\tprintf("Input x,y: ");\n\tscanf("%d,%d",&place.x,&place.y);\n\tprintf("place is (%d,%d).",place.x,place.y);\n}\n\n# 还可使用 : num 定义结构体内元素占用空间大小\n```\n\n### 结构体指针\n\n```c\n#include <stdio.h>\n\nstruct point* StructInput(struct point *p);\n\nstruct point {\n\tint x;\n\tint y;\n};\n\nint main()\n{\n\tstruct point place;\n\t// StructInput(&place);\n    printf("x is: %d\\n",(*StructInput(&place)).x);\n\tprintf("place is (%d,%d).",place.x,place.y);\n}\n\nstruct point* StructInput(struct point *p)\n{\n\tprintf("Input x,y: ");\n\tscanf("%d,%d",&p->x,&(*p).y);\n\treturn p;\n}\n\n/*\nInput x,y: 3,4\nx is: 3\nplace is (3,4).\n*/\n```\n\n## 可变数组\n\n```c\n#include <stdio.h>\n#include <stdlib.h>\n\n\ntypedef struct {\n\tint *array;\n\tint size;\n} Array;\n\nArray array_creat(int init_size){\n\tArray a;\n\ta.size = init_size;\n\ta.array = (int*)malloc(sizeof(int)*a.size);\n\treturn a;\n}\n\nvoid array_free(Array *a){\n\tfree(a->array);\n\ta->array = NULL;\n\ta->size = 0;\n}\n\nint array_size(Array *a){\n\treturn a->size;\n}\n\nint * array_at(Array *a, int index){\n\treturn &(a->array[index]);\n}\n\nint main()\n{\n\tArray a = array_creat(100);\n\tprintf("%d\\n", array_size(&a));\n\t*array_at(&a,0) = 10;\n\tprintf("%d\\n", *array_at(&a,0));\n\n\treturn 0;\n}\n```\n\n'}}]);